import { ParserRegistry } from "../../../../core/parser-registry";
import { setBarBuilderConfig } from "../../../bar-builder-config";

function setRadialBarBuilderConfig() {
    setBarBuilderConfig.call(this);

    const { builderC, chart } = this;
    const { xscale, yscale, zscale, axisrotated, stacked, yaxiscolumnorder, yrangePos } = builderC;

    builderC.color = chart.seriesColor;

    /**
     * 
     * @param {*} d - data
     * @param {string} type - 'x' | 'y' | 'xy' | 'a' | 'r' | 'ra'
     */
    builderC._getXYValue = (d, type = 'a') => {
        return chart.dataObject.getXYvalue(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, d, type, zscale, yrangePos);
    }
}

function setRadialBarCommonOption() {
    const {chart } = this;
    let commonOption = this.commonOption;

    commonOption.barSeriesCount =  chart.dataObject.noofBarEnabledSeries;


}

export function radialbar_config() {
    setRadialBarCommonOption.call(this);
    setRadialBarBuilderConfig.call(this);
}

ParserRegistry.config('radialbar', radialbar_config);